import { describe, it, expect } from "vitest";
import { quote } from "./quote.js";

describe("quote", () => {
  // Simplest case
  it.todo("empty item list returns 5 G (processing fee only)");

  // Single main item base premiums (with fee, newcomer 0 years / 1st contract)
  // Note: newcomer with first item also has 10% first-insurance surcharge.
  // To keep tests focused on individual base premiums, we use a long-standing
  // customer (>=2 years) with their 2nd contract to neutralise those, OR we
  // include modifiers in the expected value.

  // Single-item base premiums for a 1-year customer's 1st contract with no extras:
  // premium = base + 10% first insurance + 5 G fee
  it.todo("single sword (no modifiers, newcomer 1st contract) returns 115 G (100 base + 10 first + 5 fee)");
  it.todo("single amulet (no modifiers, newcomer 1st contract) returns 71 G (60 base + 6 first + 5 fee)");
  it.todo("single staff (no modifiers, newcomer 1st contract) returns 93 G (80 base + 8 first + 5 fee)");
  it.todo("single potion (no modifiers, newcomer 1st contract) returns 49 G (40 base + 4 first + 5 fee)");

  // Components and the building block of 3 alike components
  it.todo("1 rune returns 33 G (25 base + 2.5 first round-up = 28 + 5 fee = 33; rounded MHPCO's favor)");
  it.todo("2 runes returns 60 G (50 base + 5 first + 5 fee)");
  it.todo("3 runes (block applies) returns 71 G (60 block base + 6 first + 5 fee)");
  it.todo("4 runes (no block) returns 115 G (100 base + 10 first + 5 fee)");
  it.todo("7 runes returns 198 G (175 base + 17.5 first = 192.5 + 5 fee = 197.5 -> 198)");

  // \"Alike\" components clarification: same type only
  it.todo("2 runes + 1 moonstone returns 88 G (50+25 = 75 base + 7.5 first round up to 83 + 5 fee = 88)");
  it.todo("3 runes + 3 moonstones returns 137 G (60+60 = 120 base + 12 first + 5 fee)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet (newcomer 1st contract) returns 236 G (160 base + 50 cursed + 16 first + 5 fee = 231? validated by spec note)");

  // Modifier thresholds
  it.todo("sword with exactly enchantment 5 (newcomer 1st) returns 148 G (100 + 30 high + 13 first + 5 fee)");
  it.todo("cursed sword with exactly enchantment 5 (newcomer 1st) returns 203 G (100 + 50 cursed + 30 high + 18 first + 5 fee)");
  it.todo("sword with enchantment 4 not cursed (newcomer 1st) returns 115 G (no high-ench, 100 + 10 + 5)");

  // Loyalty (2 years) + follow-up contract: only loyalty/first-insurance/follow-up apply at policy level
  it.todo("long-standing customer (2 years), 1st contract, single sword returns 95 G (100 base - 20 loyalty + 10 first + 5 fee)");

  // Newcomer with a cursed sword integration: 165 G (no first-insurance? Spec says 10 G first insurance)
  // From spec: 100 + 50 cursed + 10 first = 160 + 5 fee = 165 G
  it.todo("newcomer with cursed sword (steel, ench 3) returns 165 G (spec integration example)");

  // Long-standing 2nd contract: 160 G
  // From spec: 100 + 50 cursed + 30 high ench - 20 loyalty + 10 first - 15 follow-up = 155 + 5 fee = 160
  it.todo("long-standing customer (3 years), 2nd contract, cursed sword ench 7 returns 160 G (spec integration example)");

  // Rounding
  it.todo("premium yielding 197.5 G rounds up to 198 G (MHPCO favor)");

  // Unknown item type
  it.todo("quote with unknown item type throws an error");
});

import { describe, it, expect } from "vitest";
import { quote } from "./quote.js";

describe("quote", () => {
  // Simplest case
  it.todo("empty item list returns 5 G (processing fee only)");

  // Single-item base premiums for a 0-year customer's 1st contract with no extras:
  // premium = base + 10% first insurance (on policy base) + 5 G fee
  it.todo("single sword (no modifiers, newcomer 1st contract) returns 115 G (100 base + 10 first + 5 fee)");
  it.todo("single amulet (no modifiers, newcomer 1st contract) returns 71 G (60 base + 6 first + 5 fee)");
  it.todo("single staff (no modifiers, newcomer 1st contract) returns 93 G (80 base + 8 first + 5 fee)");
  it.todo("single potion (no modifiers, newcomer 1st contract) returns 49 G (40 base + 4 first + 5 fee)");

  // Components and the building block of 3 alike components
  it.todo("1 rune (newcomer 1st) returns 33 G (25 base + 2.5 first = 27.5 + 5 fee = 32.5 -> 33)");
  it.todo("2 runes (newcomer 1st) returns 60 G (50 base + 5 first + 5 fee)");
  it.todo("3 runes (block applies, newcomer 1st) returns 71 G (60 block base + 6 first + 5 fee)");
  it.todo("4 runes (no block, newcomer 1st) returns 115 G (100 base + 10 first + 5 fee)");
  it.todo("7 runes (newcomer 1st) returns 198 G (175 base + 17.5 first + 5 fee = 197.5 -> 198)");

  // "Alike" components clarification: same type only
  it.todo("2 runes + 1 moonstone (newcomer 1st) returns 88 G (75 base + 7.5 first + 5 fee = 87.5 -> 88)");
  it.todo("3 runes + 3 moonstones (newcomer 1st) returns 137 G (120 base + 12 first + 5 fee)");

  // Modifier scope on multi-item policies
  // Spec: 160 base + 50 cursed = 210 G before further modifiers and fee
  // Newcomer 1st: + 16 first (10% of 160) + 5 fee = 231 G
  it.todo("cursed sword + plain amulet (newcomer 1st contract) returns 231 G (160 base + 50 cursed + 16 first + 5 fee)");

  // Modifier thresholds
  it.todo("sword with exactly enchantment 5 (newcomer 1st) returns 145 G (100 + 30 high + 10 first + 5 fee)");
  it.todo("cursed sword with exactly enchantment 5 (newcomer 1st) returns 195 G (100 + 50 cursed + 30 high + 10 first + 5 fee)");
  it.todo("sword with enchantment 4 not cursed (newcomer 1st) returns 115 G (no high-ench, 100 + 10 first + 5 fee)");

  // Loyalty exactly 2 years
  it.todo("long-standing customer (2 years), 1st contract, single sword returns 95 G (100 base - 20 loyalty + 10 first + 5 fee)");

  // Newcomer with a cursed sword integration example: 165 G
  it.todo("newcomer with cursed sword (steel, ench 3) returns 165 G (100 + 50 cursed + 10 first + 5 fee)");

  // Long-standing 2nd contract integration example: 160 G
  it.todo("long-standing customer (3 years), 2nd contract, cursed sword ench 7 returns 160 G (100 + 50 cursed + 30 high - 20 loyalty + 10 first - 15 follow-up + 5 fee)");

  // Rounding in MHPCO's favor (already verified by 7 runes / 2 runes + moonstone)
  it.todo("intermediate fractional amounts are kept as fractions; only final premium is rounded (covered by 7 runes case)");

  // Unknown item type
  it.todo("quote with unknown item type throws an error");
});

import { describe, it, expect } from "vitest";
import { claim } from "./claim.js";

describe("claim", () => {
  // Standard reimbursement (no special clauses)
  it.todo("steel sword ench 3, damage 500 G -> payout 400 G (full minus 100 deductible)");
  it.todo("rune (no enchantment, no material), damage 200 G -> payout 100 G (full minus 100 deductible)");

  // Enchantment threshold vs dragon material
  it.todo("dragon-material sword ench 8, damage 1000 G -> payout 400 G (high-ench 50% then deductible: 500 - 100)");
  it.todo("dragon-material sword ench 9, damage 1000 G -> payout 400 G (both clauses; 50% wins, then deductible)");
  it.todo("dragon-material sword ench 5, damage 800 G -> payout 700 G (only dragon clause: full reimbursement minus deductible)");
  it.todo("steel sword ench 9, damage 1000 G -> payout 400 G (only high-ench clause: 50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) -> payout 600 G (deductible applied once per damaged item)");

  // Multiple items of the same type
  it.todo("policy covers two swords, damage to both -> each entry gets its own deductible");
  it.todo("policy covers one sword but claim has two sword damages -> claim is rejected");

  // Cap exhaustion
  it.todo("policy covers sword + amulet -> insurance sum 1600 G, cap 3200 G (verified by remainingCap on a small claim)");
  it.todo("cursed sword (mod premium) -> cap 2000 G based on unmodified insurance value");
  it.todo("sword + 3 runes (block) -> insurance sum 1750 G, cap 3500 G (block discount affects premium only)");
  it.todo("sword (cap 2000) two claims of 1500 each: first claim payout 1400, cap remaining 600");
  it.todo("sword (cap 2000) two claims of 1500 each: second claim payout 600, cap remaining 0");

  // Rounding payout
  it.todo("payout calculation yielding 350.5 G rounds down to 350 G (MHPCO favor)");

  // Edge cases
  it.todo("claim references item not in policy -> throws error");
  it.todo("claim contains damage entry with negative amount -> throws error");
});

import { describe, it, expect } from "vitest";

describe("claim-office CLI (src/cli.ts)", () => {
  // End-to-end scenarios via stdin/stdout
  it.todo("runs a scenario with one quote step and writes {results: [{premium}]} to stdout");
  it.todo("schema example: amulet quote then fire claim -- writes 2 results in order");
  it.todo("newcomer + cursed sword integration scenario -- premium 165");
  it.todo("long-standing customer 2nd contract scenario -- premium 160 (steps reflect ordering)");
  it.todo("multi-step: quote then claim referencing earlier policy by index -- correct payout and remainingCap");
  it.todo("two successive claims against same policy demonstrate cap exhaustion");

  // Error paths
  it.todo("unknown item type in quote -- exits non-zero, writes error to stderr, no results on stdout");
  it.todo("claim references item not in policy -- exits non-zero, writes error to stderr");
  it.todo("claim has more damage entries of a type than the policy covers -- exits non-zero");
  it.todo("claim contains negative damage amount -- exits non-zero, writes error to stderr");
});

