export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteInput {
  customer: Customer;
  items: Item[];
  contractIndex: number;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const PROCESSING_FEE = 5;

function basePremiumOfItem(item: Item): number {
  const base = BASE_PREMIUMS[item.type];
  if (base === undefined) {
    throw new Error(`Unknown item type: ${item.type}`);
  }
  return base;
}

export function quote(input: QuoteInput): number {
  const policyBase = input.items.reduce((sum, item) => sum + basePremiumOfItem(item), 0);
  const firstInsurance = policyBase * 0.1;
  const total = policyBase + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
}

