function policyBasePremium(items: Item[]): number {
  // Group components by type to detect "blocks of 3 alike".
  const componentCounts = new Map<string, number>();
  let nonComponentBase = 0;
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      nonComponentBase += basePremiumOfItem(item);
    }
  }
  let componentBase = 0;
  for (const [type, count] of componentCounts) {
    if (count === BLOCK_SIZE) {
      componentBase += BLOCK_PREMIUM;
    } else {
      componentBase += count * basePremiumOfItem({ type });
    }
  }
  return nonComponentBase + componentBase;
}

export function quote(input: QuoteInput): number {
  // Validate item types eagerly.
  for (const item of input.items) {
    basePremiumOfItem(item);
  }
  const policyBase = policyBasePremium(input.items);
  const firstInsurance = policyBase * 0.1;
  const total = policyBase + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
}

