  for (const item of input.items) {
    basePremiumOfItem(item);
  }
  const policyBase = policyBasePremium(input.items);
  const itemSurcharges = input.items.reduce((sum, item) => sum + itemModifierSurcharge(item), 0);
  const firstInsurance = policyBase * 0.1;
  const total = policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE;
  return Math.ceil(total);
}

input.newString:
const LOYALTY_YEARS_THRESHOLD = 2;

function policyModifierAdjustment(policyBase: number, customer: Customer, contractIndex: number): number {
  let adjustment = 0;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) adjustment -= policyBase * 0.2;
  adjustment += policyBase * 0.1; // first insurance applies per quote
  if (contractIndex > 0) adjustment -= policyBase * 0.15;
  return adjustment;
}

export function quote(input: QuoteInput): number {
  for (const item of input.items) {
    basePremiumOfItem(item);
  }
  const policyBase = policyBasePremium(input.items);
  const itemSurcharges = input.items.reduce((sum, item) => sum + itemModifierSurcharge(item), 0);
  const policyAdjustment = policyModifierAdjustment(policyBase, input.customer, input.contractIndex);
  const total = policyBase + itemSurcharges + policyAdjustment + PROCESSING_FEE;
  return Math.ceil(total);
}

