import type { Item } from "./quote.js";

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface Policy {
  items: Item[];
  remainingCap: number;
}

export interface ClaimInput {
  policy: Policy;
  incident: Incident;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export function claim(_input: ClaimInput): ClaimResult {
  return { payout: 0, remainingCap: 0 };
}

