const DEDUCTIBLE = 100;

export function claim(input: ClaimInput): ClaimResult {
  let totalPayout = 0;
  for (const damage of input.incident.damages) {
    const itemPayout = Math.max(0, damage.amount - DEDUCTIBLE);
    totalPayout += itemPayout;
  }
  return { payout: totalPayout, remainingCap: input.policy.remainingCap - totalPayout };
}

