function countByKey<T>(values: T[], keyOf: (v: T) => string): Map<string, number> {
  const counts = new Map<string, number>();
  for (const v of values) {
    const key = keyOf(v);
    counts.set(key, (counts.get(key) ?? 0) + 1);
  }
  return counts;
}

